use std::fs::{create_dir_all, write};
use std::path::Path;

use dinoco_compiler::{ParsedFieldType, ParsedSchema, ParsedTable};

use super::helpers::{filter_type, relation_fields, relation_target, rust_scalar_type, scalar_fields, to_snake_case};
use super::relations::{RelationCardinality, resolve_relation};
use super::render_dinoco::render_dinoco_module;
use super::render_enums::render_enums;

const GENERATED_FILE_BANNER: &str = "// ==============================================================\n\
// =================== DINOCO MANAGED FILE =======================\n\
// ==============================================================\n\
// This file is generated and managed by Dinoco.\n\
// Do not edit this file manually.\n\
// Any manual changes will be overwritten the next time Dinoco runs.\n\
// ==============================================================\n\n";
const GENERATED_FILE_LINTS: &str = "#![allow(dead_code)]\n#![allow(non_camel_case_types)]\n#![allow(non_snake_case)]\n#![allow(non_upper_case_globals)]\n#![allow(unused_imports)]\n#![allow(unused_variables)]\n\n";

pub fn generate_models(schema: ParsedSchema) {
    let dinoco_dir = Path::new("dinoco");
    let output_dir = dinoco_dir.join("models");

    if output_dir.exists() {
        std::fs::remove_dir_all(&output_dir).unwrap();
    }

    create_dir_all(&output_dir).unwrap();
    write(dinoco_dir.join("mod.rs"), render_dinoco_module(&schema)).unwrap();

    let mut module_exports = Vec::new();
    let mut enum_names = Vec::new();

    if !schema.enums.is_empty() {
        let enum_file = render_enums(&schema);

        write(output_dir.join("enums.rs"), enum_file).unwrap();
        module_exports.push("pub mod enums;".to_string());
        module_exports.push("pub use enums::*;".to_string());

        enum_names.extend(schema.enums.iter().map(|item| item.name.clone()));
    }

    for table in &schema.tables {
        let file_name = to_snake_case(&table.name);
        let file_path = output_dir.join(format!("{file_name}.rs"));
        let model_file = render_model(table, &schema, &enum_names);

        write(file_path, model_file).unwrap();
        module_exports.push(format!("pub mod {file_name};"));
        module_exports.push(format!("pub use {file_name}::*;"));
    }

    write(output_dir.join("mod.rs"), format!("{GENERATED_FILE_BANNER}{GENERATED_FILE_LINTS}{}", module_exports.join("\n")))
        .unwrap();
}

fn render_model(table: &ParsedTable, schema: &ParsedSchema, enum_names: &[String]) -> String {
    let name = &table.name;
    let fields = &table.fields;
    let scalar_fields = scalar_fields(fields);
    let relation_fields = relation_fields(fields);
    let relation_imports = relation_fields
        .iter()
        .filter_map(|field| {
            let ParsedFieldType::Relation(target) = &field.field_type else {
                return None;
            };

            Some(format!("{}::{}", to_snake_case(target), target))
        })
        .collect::<Vec<_>>();

    let mut output = String::from(GENERATED_FILE_BANNER);

    output.push_str(GENERATED_FILE_LINTS);

    output.push_str("use dinoco::{Model, Projection, RelationField, Rowable, ScalarField};\n");

    if !relation_imports.is_empty() {
        output.push_str(&format!("use super::{{{}}};\n", relation_imports.join(", ")));
    }

    output.push('\n');
    output.push_str("#[derive(Debug, Clone, Rowable)]\n");
    output.push_str(&format!("pub struct {} {{\n", name));

    for field in &scalar_fields {
        output.push_str(&format!("    pub {}: {},\n", field.name, rust_scalar_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&format!("pub struct {}Where {{\n", name));

    for field in &scalar_fields {
        output.push_str(&format!("    pub {}: ScalarField<{}>,\n", field.name, filter_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&format!("pub struct {}Include {}\n\n", name, "{}"));
    output.push_str(&format!("impl Projection<{}> for {} {{\n", name, name));
    output.push_str("    fn columns() -> &'static [&'static str] {\n");
    output.push_str("        &[\n");

    for field in &scalar_fields {
        output.push_str(&format!("            \"{}\",\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Where {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {\n");

    for field in &scalar_fields {
        output.push_str(&format!("            {}: ScalarField::new(\"{}\"),\n", field.name, field.name));
    }

    output.push_str("        }\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Include {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {}\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl {}Include {{\n", name));

    for field in &relation_fields {
        output.push_str(&format!("    pub fn {}(&self) -> RelationField<{}> {{\n", field.name, relation_target(field)));
        output.push_str(&format!("        RelationField::new(\"{}\")\n", field.name));
        output.push_str("    }\n");
    }

    output.push_str("}\n\n");
    output.push_str(&render_relation_loaders(table, schema));
    output.push_str(&format!("impl Model for {} {{\n", name));
    output.push_str(&format!("    type Include = {}Include;\n", name));
    output.push_str(&format!("    type Where = {}Where;\n\n", name));
    output.push_str("    fn table_name() -> &'static str {\n");
    output.push_str(&format!("        \"{}\"\n", table.database_name));
    output.push_str("    }\n");
    output.push_str("}\n");

    output
}

fn render_relation_loaders(table: &ParsedTable, schema: &ParsedSchema) -> String {
    let mut output = String::new();

    for field in relation_fields(&table.fields) {
        let Some(relation) = resolve_relation(table, field, schema) else {
            continue;
        };

        let loader_name = format!("__dinoco_load_{}", field.name);
        let local_key_ty = rust_scalar_type(relation.local_key_field, &[]);
        let remote_key_ty = rust_scalar_type(relation.remote_key_field, &[]);
        let target_model = relation_target(field);
        let remote_key_ident = &relation.remote_key_field.name;
        let statement_table = &relation.target_table_name;

        let block = match relation.cardinality {
            RelationCardinality::Many => render_many_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
            ),
            RelationCardinality::OptionalOne => render_optional_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
            ),
            RelationCardinality::ManyToMany {
                ref join_table_name,
                ref current_join_column,
                ref target_join_column,
            } => render_many_to_many_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &remote_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
                join_table_name,
                current_join_column,
                target_join_column,
            ),
        };

        output.push_str(&block);
    }

    output
}

fn render_many_loader(
    model_name: &str,
    loader_name: &str,
    local_key_ty: &str,
    target_model: &str,
    remote_key_ident: &str,
    statement_table: &str,
) -> String {
    format!(
        "impl {model_name} {{\n    pub fn {loader_name}<'a, P, C, A>(\n        item_keys: Vec<Option<{local_key_ty}>>,\n        include: &'a dinoco::IncludeNode,\n        client: &'a dinoco::DinocoClient<A>,\n        read_mode: dinoco::ReadMode,\n        relation_field: impl Fn(&mut P) -> &mut Vec<C> + Copy + 'a,\n    ) -> dinoco::IncludeLoaderFuture<'a, P>\n    where\n        A: dinoco::DinocoAdapter,\n        C: dinoco::Projection<{target_model}>,\n    {{\n        Box::pin(async move {{\n            use std::collections::HashMap;\n\n            struct DinocoChildRow<C> {{\n                item: C,\n                relation_key: {local_key_ty},\n            }}\n\n            impl<C> dinoco::DinocoRow for DinocoChildRow<C>\n            where\n                C: dinoco::Projection<{target_model}>,\n            {{\n                fn from_row<R: dinoco::DinocoGenericRow>(row: &R) -> dinoco::DinocoResult<Self> {{\n                    Ok(Self {{\n                        item: C::from_row(row)?,\n                        relation_key: row.get(C::columns().len())?,\n                    }})\n                }}\n            }}\n\n            let keys = item_keys.iter().flatten().cloned().collect::<Vec<_>>();\n\n            if keys.is_empty() {{\n                return Ok(Box::new(|_: &mut [P]| {{}}) as dinoco::IncludeApplier<'a, P>);\n            }}\n\n            let mut statement = include.statement.clone().unwrap_or_else(|| dinoco_engine::SelectStatement::new().from({statement_table:?}).select(C::columns()));\n            let mut select_columns = C::columns().iter().map(|column| column.to_string()).collect::<Vec<_>>();\n\n            if !select_columns.iter().any(|column| column == {remote_key_ident:?}) {{\n                select_columns.push({remote_key_ident:?}.to_string());\n            }}\n\n            statement.select = select_columns;\n            statement.conditions.push(dinoco_engine::Expression::Column({remote_key_ident:?}.to_string()).in_values(keys.iter().cloned().map(dinoco::IntoDinocoValue::into_dinoco_value).collect()));\n\n            let adapter = client.read_adapter(matches!(read_mode, dinoco::ReadMode::Primary));\n            let (sql, params) = dinoco_engine::QueryBuilder::build_select(adapter.dialect(), &statement);\n            let child_rows = adapter.query_as::<DinocoChildRow<C>>(&sql, &params).await?;\n            let relation_keys = child_rows.iter().map(|row| row.relation_key.clone()).collect::<Vec<_>>();\n            let mut children = child_rows.into_iter().map(|row| row.item).collect::<Vec<_>>();\n\n            C::load_includes(&mut children, &include.includes, client, read_mode).await?;\n\n            let mut grouped: HashMap<{local_key_ty}, Vec<C>> = HashMap::new();\n\n            for (relation_key, child) in relation_keys.into_iter().zip(children.into_iter()) {{\n                grouped.entry(relation_key).or_default().push(child);\n            }}\n\n            Ok(Box::new(move |items: &mut [P]| {{\n                for (item, key) in items.iter_mut().zip(item_keys.into_iter()) {{\n                    *relation_field(item) = key.and_then(|key| grouped.remove(&key)).unwrap_or_default();\n                }}\n            }}) as dinoco::IncludeApplier<'a, P>)\n        }})\n    }}\n}}\n\n"
    )
}

fn render_optional_loader(
    model_name: &str,
    loader_name: &str,
    local_key_ty: &str,
    target_model: &str,
    remote_key_ident: &str,
    statement_table: &str,
) -> String {
    format!(
        "impl {model_name} {{\n    pub fn {loader_name}<'a, P, C, A>(\n        item_keys: Vec<Option<{local_key_ty}>>,\n        include: &'a dinoco::IncludeNode,\n        client: &'a dinoco::DinocoClient<A>,\n        read_mode: dinoco::ReadMode,\n        relation_field: impl Fn(&mut P) -> &mut Option<C> + Copy + 'a,\n    ) -> dinoco::IncludeLoaderFuture<'a, P>\n    where\n        A: dinoco::DinocoAdapter,\n        C: dinoco::Projection<{target_model}>,\n    {{\n        Box::pin(async move {{\n            use std::collections::HashMap;\n\n            struct DinocoChildRow<C> {{\n                item: C,\n                relation_key: {local_key_ty},\n            }}\n\n            impl<C> dinoco::DinocoRow for DinocoChildRow<C>\n            where\n                C: dinoco::Projection<{target_model}>,\n            {{\n                fn from_row<R: dinoco::DinocoGenericRow>(row: &R) -> dinoco::DinocoResult<Self> {{\n                    Ok(Self {{\n                        item: C::from_row(row)?,\n                        relation_key: row.get(C::columns().len())?,\n                    }})\n                }}\n            }}\n\n            let keys = item_keys.iter().flatten().cloned().collect::<Vec<_>>();\n\n            if keys.is_empty() {{\n                return Ok(Box::new(|_: &mut [P]| {{}}) as dinoco::IncludeApplier<'a, P>);\n            }}\n\n            let mut statement = include.statement.clone().unwrap_or_else(|| dinoco_engine::SelectStatement::new().from({statement_table:?}).select(C::columns()));\n            let mut select_columns = C::columns().iter().map(|column| column.to_string()).collect::<Vec<_>>();\n\n            if !select_columns.iter().any(|column| column == {remote_key_ident:?}) {{\n                select_columns.push({remote_key_ident:?}.to_string());\n            }}\n\n            statement.select = select_columns;\n            statement.conditions.push(dinoco_engine::Expression::Column({remote_key_ident:?}.to_string()).in_values(keys.iter().cloned().map(dinoco::IntoDinocoValue::into_dinoco_value).collect()));\n\n            let adapter = client.read_adapter(matches!(read_mode, dinoco::ReadMode::Primary));\n            let (sql, params) = dinoco_engine::QueryBuilder::build_select(adapter.dialect(), &statement);\n            let child_rows = adapter.query_as::<DinocoChildRow<C>>(&sql, &params).await?;\n            let relation_keys = child_rows.iter().map(|row| row.relation_key.clone()).collect::<Vec<_>>();\n            let mut children = child_rows.into_iter().map(|row| row.item).collect::<Vec<_>>();\n\n            C::load_includes(&mut children, &include.includes, client, read_mode).await?;\n\n            let mut grouped: HashMap<{local_key_ty}, C> = HashMap::new();\n\n            for (relation_key, child) in relation_keys.into_iter().zip(children.into_iter()) {{\n                grouped.insert(relation_key, child);\n            }}\n\n            Ok(Box::new(move |items: &mut [P]| {{\n                for (item, key) in items.iter_mut().zip(item_keys.into_iter()) {{\n                    *relation_field(item) = key.and_then(|key| grouped.remove(&key));\n                }}\n            }}) as dinoco::IncludeApplier<'a, P>)\n        }})\n    }}\n}}\n\n"
    )
}

fn render_many_to_many_loader(
    model_name: &str,
    loader_name: &str,
    local_key_ty: &str,
    remote_key_ty: &str,
    target_model: &str,
    remote_key_ident: &str,
    statement_table: &str,
    join_table_name: &str,
    current_join_column: &str,
    target_join_column: &str,
) -> String {
    format!(
        "impl {model_name} {{\n    pub fn {loader_name}<'a, P, C, A>(\n        item_keys: Vec<Option<{local_key_ty}>>,\n        include: &'a dinoco::IncludeNode,\n        client: &'a dinoco::DinocoClient<A>,\n        read_mode: dinoco::ReadMode,\n        relation_field: impl Fn(&mut P) -> &mut Vec<C> + Copy + 'a,\n    ) -> dinoco::IncludeLoaderFuture<'a, P>\n    where\n        A: dinoco::DinocoAdapter,\n        C: dinoco::Projection<{target_model}> + Clone,\n    {{\n        Box::pin(async move {{\n            use std::collections::HashMap;\n\n            #[derive(Debug, Clone, dinoco::Rowable)]\n            struct DinocoJoinRow {{\n                {current_join_column}: {local_key_ty},\n                {target_join_column}: {remote_key_ty},\n            }}\n\n            struct DinocoChildRow<C> {{\n                item: C,\n                relation_key: {remote_key_ty},\n            }}\n\n            impl<C> dinoco::DinocoRow for DinocoChildRow<C>\n            where\n                C: dinoco::Projection<{target_model}>,\n            {{\n                fn from_row<R: dinoco::DinocoGenericRow>(row: &R) -> dinoco::DinocoResult<Self> {{\n                    Ok(Self {{\n                        item: C::from_row(row)?,\n                        relation_key: row.get(C::columns().len())?,\n                    }})\n                }}\n            }}\n\n            let keys = item_keys.iter().flatten().cloned().collect::<Vec<_>>();\n\n            if keys.is_empty() {{\n                return Ok(Box::new(|_: &mut [P]| {{}}) as dinoco::IncludeApplier<'a, P>);\n            }}\n\n            let join_statement = dinoco_engine::SelectStatement::new()\n                .from({join_table_name:?})\n                .select(&[{current_join_column:?}, {target_join_column:?}])\n                .condition(dinoco_engine::Expression::Column({current_join_column:?}.to_string()).in_values(keys.iter().cloned().map(dinoco::IntoDinocoValue::into_dinoco_value).collect()));\n\n            let adapter = client.read_adapter(matches!(read_mode, dinoco::ReadMode::Primary));\n            let (join_sql, join_params) = dinoco_engine::QueryBuilder::build_select(adapter.dialect(), &join_statement);\n            let join_rows = adapter.query_as::<DinocoJoinRow>(&join_sql, &join_params).await?;\n            let target_ids = join_rows.iter().map(|row| row.{target_join_column}.clone()).collect::<Vec<_>>();\n\n            if target_ids.is_empty() {{\n                return Ok(Box::new(|items: &mut [P]| {{\n                    for item in items.iter_mut() {{\n                        relation_field(item).clear();\n                    }}\n                }}) as dinoco::IncludeApplier<'a, P>);\n            }}\n\n            let mut statement = include.statement.clone().unwrap_or_else(|| dinoco_engine::SelectStatement::new().from({statement_table:?}).select(C::columns()));\n            let mut select_columns = C::columns().iter().map(|column| column.to_string()).collect::<Vec<_>>();\n\n            if !select_columns.iter().any(|column| column == {remote_key_ident:?}) {{\n                select_columns.push({remote_key_ident:?}.to_string());\n            }}\n\n            statement.select = select_columns;\n            statement.conditions.push(dinoco_engine::Expression::Column({remote_key_ident:?}.to_string()).in_values(target_ids.iter().cloned().map(dinoco::IntoDinocoValue::into_dinoco_value).collect()));\n\n            let (sql, params) = dinoco_engine::QueryBuilder::build_select(adapter.dialect(), &statement);\n            let child_rows = adapter.query_as::<DinocoChildRow<C>>(&sql, &params).await?;\n            let relation_keys = child_rows.iter().map(|row| row.relation_key.clone()).collect::<Vec<_>>();\n            let mut children = child_rows.into_iter().map(|row| row.item).collect::<Vec<_>>();\n\n            C::load_includes(&mut children, &include.includes, client, read_mode).await?;\n\n            let mut child_map: HashMap<{remote_key_ty}, C> = HashMap::new();\n\n            for (relation_key, child) in relation_keys.into_iter().zip(children.into_iter()) {{\n                child_map.insert(relation_key, child);\n            }}\n\n            let mut grouped: HashMap<{local_key_ty}, Vec<C>> = HashMap::new();\n\n            for join_row in join_rows {{\n                if let Some(child) = child_map.get(&join_row.{target_join_column}) {{\n                    grouped.entry(join_row.{current_join_column}.clone()).or_default().push(child.clone());\n                }}\n            }}\n\n            Ok(Box::new(move |items: &mut [P]| {{\n                for (item, key) in items.iter_mut().zip(item_keys.into_iter()) {{\n                    *relation_field(item) = key.and_then(|key| grouped.remove(&key)).unwrap_or_default();\n                }}\n            }}) as dinoco::IncludeApplier<'a, P>)\n        }})\n    }}\n}}\n\n"
    )
}
